import React from 'react';
import { useNavigate } from 'react-router-dom';
import { FiStar, FiClock, FiHeart } from 'react-icons/fi';
import { useAuth } from '../../context/AuthContext';
import { authAPI } from '../../utils/api';
import toast from 'react-hot-toast';

export default function ServiceCard({ service, showSave = true }) {
  const navigate = useNavigate();
  const { isLoggedIn, user, updateUser } = useAuth();

  const isSaved = user?.savedServices?.some(s => (s._id || s) === service._id);

  const handleSave = async (e) => {
    e.stopPropagation();
    if (!isLoggedIn) { toast.error('Please login to save services'); navigate('/login'); return; }
    try {
      const { data } = await authAPI.toggleSavedService(service._id);
      const updated = { ...user };
      if (data.saved) {
        updated.savedServices = [...(user.savedServices || []), service._id];
        toast.success('Saved to favourites ❤️');
      } else {
        updated.savedServices = (user.savedServices || []).filter(s => (s._id || s) !== service._id);
        toast.success('Removed from favourites');
      }
      updateUser(updated);
    } catch { toast.error('Failed to update'); }
  };

  const categoryEmoji = {
    'Cleaning Services': '🧹', 'Repair & Maintenance': '🔧',
    'Home Improvement': '🎨', 'Outdoor Services': '🌿',
    'Personal & Care Services': '💆', 'Convenience Services': '🍳',
    'Smart Home & Tech Services': '📱',
  };

  return (
    <div className="card" style={{ cursor: 'pointer', position: 'relative', display: 'flex', flexDirection: 'column' }}
      onClick={() => navigate(`/services/${service._id}`)}>
      {/* Image / emoji area */}
      <div style={{
        height: 140, background: 'linear-gradient(135deg, var(--primary-light), #EDE9FE)',
        display: 'flex', alignItems: 'center', justifyContent: 'center',
        fontSize: 56, position: 'relative'
      }}>
        <span>{categoryEmoji[service.category] || '🏠'}</span>
        {service.isBestseller && (
          <span style={{ position: 'absolute', top: 12, left: 12 }} className="badge badge-green">BESTSELLER</span>
        )}
        {showSave && isLoggedIn && (
          <button onClick={handleSave} style={{
            position: 'absolute', top: 12, right: 12,
            background: 'white', border: 'none', borderRadius: '50%',
            width: 34, height: 34, display: 'flex', alignItems: 'center', justifyContent: 'center',
            cursor: 'pointer', boxShadow: 'var(--shadow-sm)', transition: 'all 0.2s'
          }}>
            <FiHeart size={16} fill={isSaved ? '#EF4444' : 'none'} color={isSaved ? '#EF4444' : '#9CA3AF'} />
          </button>
        )}
      </div>

      {/* Content */}
      <div style={{ padding: '16px', flex: 1, display: 'flex', flexDirection: 'column', gap: 8 }}>
        <div style={{ fontSize: 12, color: 'var(--primary)', fontWeight: 600, fontFamily: 'var(--font-display)' }}>
          {service.category}
        </div>
        <h3 style={{ fontSize: 15, fontWeight: 700, lineHeight: 1.3, fontFamily: 'var(--font-display)', color: 'var(--text-primary)' }}>
          {service.name}
        </h3>
        <p style={{ fontSize: 13, color: 'var(--text-secondary)', lineHeight: 1.5, flex: 1 }}>
          {service.description?.slice(0, 80)}...
        </p>
        <div style={{ display: 'flex', alignItems: 'center', gap: 12, fontSize: 13, color: 'var(--text-muted)' }}>
          <span style={{ display: 'flex', alignItems: 'center', gap: 4 }}>
            <FiStar size={13} color="#FFB547" fill="#FFB547" />
            <strong style={{ color: 'var(--text-primary)' }}>{service.rating || '4.8'}</strong>
            ({service.totalReviews >= 1000 ? `${(service.totalReviews / 1000).toFixed(0)}k` : service.totalReviews})
          </span>
          <span style={{ display: 'flex', alignItems: 'center', gap: 4 }}>
            <FiClock size={13} /> {service.duration}
          </span>
        </div>
        <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginTop: 4 }}>
          <div>
            <span style={{ fontSize: 20, fontWeight: 800, color: 'var(--primary)', fontFamily: 'var(--font-display)' }}>₹{service.price}</span>
            {service.originalPrice > service.price && (
              <span style={{ fontSize: 13, color: 'var(--text-muted)', textDecoration: 'line-through', marginLeft: 6 }}>₹{service.originalPrice}</span>
            )}
          </div>
          <button className="btn btn-primary btn-sm" onClick={e => { e.stopPropagation(); navigate(`/services/${service._id}`); }}>
            Book
          </button>
        </div>
      </div>
    </div>
  );
}
